export const GUIDED_SHOT_IDS = [
  "setup",
  "meter_box",
  "switchboard",
  "serial_plate",
  "battery_label",
  "testing",
] as const;

export type GuidedShotId = (typeof GUIDED_SHOT_IDS)[number];

export interface EvidencePackRecord {
  shotId: string;
  capturedAt: string;
  lat: number | null;
  lng: number | null;
  evidenceType: string;
  frameId: string;
  storageRef: string;
  zipEntry: string;
}

export interface EvidencePackManifest {
  sessionId: string;
  generatedAt: string;
  progress: { done: number; total: number };
  records: EvidencePackRecord[];
  note: string;
}

export interface StampFieldStatus {
  shotId: string;
  capturedAt: boolean;
  hasGps: boolean;
}

export interface PackValidationReport {
  ok: boolean;
  sessionId: string | null;
  progress: { done: number; total: number } | null;
  presentShots: string[];
  missingShots: string[];
  stampFieldsPresent: StampFieldStatus[];
  errors: string[];
}

const LOCAL_HEADER_SIGNATURE = 0x04034b50;
const END_OF_CENTRAL_DIR_SIGNATURE = 0x06054b50;

function crc32(data: Uint8Array): number {
  let crc = 0xffffffff;
  for (let i = 0; i < data.length; i++) {
    crc ^= data[i]!;
    for (let j = 0; j < 8; j++) {
      crc = (crc >>> 1) ^ (crc & 1 ? 0xedb88320 : 0);
    }
  }
  return (crc ^ 0xffffffff) >>> 0;
}

function readZipArchive(zipBytes: Uint8Array): Array<{ name: string; data: Uint8Array }> {
  const entries: Array<{ name: string; data: Uint8Array }> = [];
  let offset = 0;

  while (offset + 30 <= zipBytes.length) {
    const view = new DataView(zipBytes.buffer, zipBytes.byteOffset, zipBytes.byteLength);
    const signature = view.getUint32(offset, true);
    if (signature === END_OF_CENTRAL_DIR_SIGNATURE) break;
    if (signature !== LOCAL_HEADER_SIGNATURE) {
      throw new Error(`Invalid ZIP local header at offset ${offset}`);
    }

    const compressionMethod = view.getUint16(offset + 8, true);
    const compressedSize = view.getUint32(offset + 18, true);
    const uncompressedSize = view.getUint32(offset + 22, true);
    const nameLength = view.getUint16(offset + 26, true);
    const extraLength = view.getUint16(offset + 28, true);
    const nameStart = offset + 30;
    const nameEnd = nameStart + nameLength;
    const dataStart = nameEnd + extraLength;
    const dataEnd = dataStart + compressedSize;

    const name = new TextDecoder().decode(zipBytes.subarray(nameStart, nameEnd));
    const data = zipBytes.subarray(dataStart, dataEnd);

    if (compressionMethod !== 0) {
      throw new Error(`Unsupported ZIP compression for ${name}`);
    }
    if (compressedSize !== uncompressedSize) {
      throw new Error(`ZIP size mismatch for ${name}`);
    }

    entries.push({ name, data });
    offset = dataEnd;
  }

  return entries;
}

function createZipArchive(entries: ReadonlyArray<{ name: string; data: Uint8Array }>): Uint8Array {
  const parts: Uint8Array[] = [];
  const centralParts: Uint8Array[] = [];
  let offset = 0;

  for (const entry of entries) {
    const nameBytes = new TextEncoder().encode(entry.name);
    const data = entry.data;
    const checksum = crc32(data);

    const local = new Uint8Array(30 + nameBytes.length);
    const localView = new DataView(local.buffer);
    localView.setUint32(0, LOCAL_HEADER_SIGNATURE, true);
    localView.setUint16(4, 20, true);
    localView.setUint32(14, checksum, true);
    localView.setUint32(18, data.length, true);
    localView.setUint32(22, data.length, true);
    localView.setUint16(26, nameBytes.length, true);
    local.set(nameBytes, 30);

    const central = new Uint8Array(46 + nameBytes.length);
    const centralView = new DataView(central.buffer);
    centralView.setUint32(0, 0x02014b50, true);
    centralView.setUint16(4, 20, true);
    centralView.setUint16(6, 20, true);
    centralView.setUint32(16, checksum, true);
    centralView.setUint32(20, data.length, true);
    centralView.setUint32(24, data.length, true);
    centralView.setUint16(28, nameBytes.length, true);
    centralView.setUint32(42, offset, true);
    central.set(nameBytes, 46);

    parts.push(local, data);
    centralParts.push(central);
    offset += local.length + data.length;
  }

  const centralDir = concatUint8(centralParts);
  const end = new Uint8Array(22);
  const endView = new DataView(end.buffer);
  endView.setUint32(0, END_OF_CENTRAL_DIR_SIGNATURE, true);
  endView.setUint16(8, entries.length, true);
  endView.setUint16(10, entries.length, true);
  endView.setUint32(12, centralDir.length, true);
  endView.setUint32(16, offset, true);

  return concatUint8([...parts, centralDir, end]);
}

function concatUint8(chunks: Uint8Array[]): Uint8Array {
  const total = chunks.reduce((sum, c) => sum + c.length, 0);
  const out = new Uint8Array(total);
  let pos = 0;
  for (const chunk of chunks) {
    out.set(chunk, pos);
    pos += chunk.length;
  }
  return out;
}

function dataUrlToBytes(dataUrl: string): Uint8Array {
  const comma = dataUrl.indexOf(",");
  const b64 = dataUrl.slice(comma + 1);
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

function looksLikeJpeg(data: Uint8Array): boolean {
  return data.length >= 3 && data[0] === 0xff && data[1] === 0xd8 && data[2] === 0xff;
}

function isGuidedShotId(value: string): value is GuidedShotId {
  return (GUIDED_SHOT_IDS as readonly string[]).includes(value);
}

function shotIdFromZipEntry(zipEntry: string): string {
  const slash = zipEntry.lastIndexOf("/");
  const base = slash >= 0 ? zipEntry.slice(slash + 1) : zipEntry;
  const dot = base.lastIndexOf(".");
  return dot >= 0 ? base.slice(0, dot) : base;
}

export function buildDemoEvidenceManifest(
  records: EvidencePackRecord[],
  generatedAt = new Date().toISOString(),
): EvidencePackManifest {
  const uniqueShots = new Set(records.map((r) => r.shotId));
  return {
    sessionId: DEMO_SESSION_ID,
    generatedAt,
    progress: { done: uniqueShots.size, total: GUIDED_SHOT_IDS.length },
    records,
    note: "C1 demo pack — A1 fixture JPEGs with stamped metadata.",
  };
}

export function buildDemoEvidencePackZip(
  captures: ReadonlyArray<{ shotId: ComplianceShotId; imageSrc: string; capturedAt: string }>,
): Uint8Array {
  const records: EvidencePackRecord[] = captures.map((cap, index) => ({
    shotId: cap.shotId,
    capturedAt: cap.capturedAt,
    lat: -33.8688,
    lng: 151.2093,
    evidenceType: cap.shotId,
    frameId: `demo-frame-${index}`,
    storageRef: `demo/${cap.shotId}.jpg`,
    zipEntry: `${cap.shotId}.jpg`,
  }));

  const manifest = buildDemoEvidenceManifest(records);
  const entries: Array<{ name: string; data: Uint8Array }> = [
    {
      name: "manifest.json",
      data: new TextEncoder().encode(JSON.stringify(manifest, null, 2)),
    },
  ];

  for (const cap of captures) {
    entries.push({ name: `${cap.shotId}.jpg`, data: dataUrlToBytes(cap.imageSrc) });
  }

  return createZipArchive(entries);
}

/** Mirrors backend pack-validator rules (A3) for offline demo. */
export function validateDemoEvidencePack(zipBytes: Uint8Array): PackValidationReport {
  const errors: string[] = [];
  let sessionId: string | null = null;
  let progress: { done: number; total: number } | null = null;
  const presentShots = new Set<string>();
  const stampFieldsPresent: StampFieldStatus[] = [];

  let entries: Array<{ name: string; data: Uint8Array }>;
  try {
    entries = readZipArchive(zipBytes);
  } catch (err) {
    return {
      ok: false,
      sessionId: null,
      progress: null,
      presentShots: [],
      missingShots: [...GUIDED_SHOT_IDS],
      stampFieldsPresent: [],
      errors: [err instanceof Error ? err.message : "Failed to read ZIP archive"],
    };
  }

  const files = new Map(entries.map((e) => [e.name, e.data]));
  const manifestRaw = files.get("manifest.json");
  if (!manifestRaw) {
    return {
      ok: false,
      sessionId: null,
      progress: null,
      presentShots: [],
      missingShots: [...GUIDED_SHOT_IDS],
      stampFieldsPresent: [],
      errors: ["Missing manifest.json"],
    };
  }

  let manifest: EvidencePackManifest;
  try {
    manifest = JSON.parse(new TextDecoder().decode(manifestRaw)) as EvidencePackManifest;
  } catch {
    return {
      ok: false,
      sessionId: null,
      progress: null,
      presentShots: [],
      missingShots: [...GUIDED_SHOT_IDS],
      stampFieldsPresent: [],
      errors: ["Invalid manifest.json"],
    };
  }

  sessionId = manifest.sessionId;
  progress = manifest.progress ?? null;
  const seenShotIds = new Set<string>();

  for (const [index, record] of manifest.records.entries()) {
    const label = `records[${index}]`;
    const shotId = record.shotId?.trim();
    if (!shotId || !isGuidedShotId(shotId)) {
      errors.push(`${label}: unknown shotId "${record.shotId}"`);
      continue;
    }
    if (!record.capturedAt?.trim()) {
      errors.push(`${label}: missing capturedAt for shot "${shotId}"`);
    }
    if (seenShotIds.has(shotId)) {
      errors.push(`${label}: duplicate shotId "${shotId}"`);
    }
    seenShotIds.add(shotId);

    const entryShotId = shotIdFromZipEntry(record.zipEntry);
    if (entryShotId !== shotId) {
      errors.push(`${label}: shotId "${shotId}" does not match zipEntry "${record.zipEntry}"`);
    }

    const jpeg = files.get(record.zipEntry);
    if (!jpeg) {
      errors.push(`${label}: missing JPEG "${record.zipEntry}"`);
      continue;
    }
    if (!looksLikeJpeg(jpeg)) {
      errors.push(`${label}: "${record.zipEntry}" is not a JPEG`);
    }

    presentShots.add(shotId);
    stampFieldsPresent.push({
      shotId,
      capturedAt: Boolean(record.capturedAt?.trim()),
      hasGps: record.lat !== null && record.lng !== null,
    });
  }

  const missingShots = GUIDED_SHOT_IDS.filter((id) => !presentShots.has(id));
  if (missingShots.length > 0) {
    errors.push(`Missing guided shots: ${missingShots.join(", ")}`);
  }

  return {
    ok: errors.length === 0,
    sessionId,
    progress,
    presentShots: [...presentShots],
    missingShots,
    stampFieldsPresent,
    errors,
  };
}

export function formatPackValidationReport(report: PackValidationReport): string {
  const lines = [
    report.ok ? "PASS" : "FAIL",
    `sessionId: ${report.sessionId ?? "(none)"}`,
  ];
  if (report.progress) {
    lines.push(`progress: ${report.progress.done}/${report.progress.total}`);
  }
  lines.push(`presentShots: ${report.presentShots.join(", ") || "(none)"}`);
  lines.push(`missingShots: ${report.missingShots.join(", ") || "(none)"}`);
  if (report.errors.length > 0) {
    lines.push("errors:");
    for (const error of report.errors) lines.push(`  - ${error}`);
  }
  return lines.join("\n");
}

export function demoEvidencePackFilename(): string {
  return `foreman-evidence-${DEMO_SESSION_ID.slice(0, 8)}.zip`;
}

export function downloadDemoEvidencePack(zipBytes: Uint8Array): void {
  if (typeof window === "undefined") return;
  const blob = new Blob([zipBytes.slice()], { type: "application/zip" });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = url;
  anchor.download = demoEvidencePackFilename();
  anchor.click();
  URL.revokeObjectURL(url);
}
